interface BlogPost {
  id: number;
  title: string;
  content: string;
  author: string;
  publishedAt?: string;   // optional
  tags?: string[];        // optional
}

function formatPost(post: BlogPost): string {
  const date = post.publishedAt ?? "draft";
  const tags = post.tags?.join(", ") ?? "none";
  return `[${date}] ${post.title} by ${post.author} — tags: ${tags}`;
}

const published: BlogPost = {
  id: 1, title: "TypeScript Tips", content: "...",
  author: "Alice", publishedAt: "2024-01-15", tags: ["ts", "programming"],
};
const draft: BlogPost = {
  id: 2, title: "SQL Guide", content: "...", author: "Bob",
};

console.log(formatPost(published));
console.log(formatPost(draft));

