// Imagine a team refactor changed 'user.fullName' to 'user.displayName'
interface User {
  id: number;
  displayName: string;  // was: fullName
  email: string;
}

function sendWelcomeEmail(user: User): string {
  // In JavaScript, 'user.fullName' would be undefined — silent bug
  // TypeScript errors immediately: Property 'fullName' does not exist
  const name = user.displayName;  // using the correct field
  return `Welcome, ${name}! Your account: ${user.email}`;
}

const alice: User = { id: 1, displayName: "Alice Chen", email: "alice@co.com" };
const bob:   User = { id: 2, displayName: "Bob Taylor", email: "bob@co.com" };

console.log(sendWelcomeEmail(alice));
console.log(sendWelcomeEmail(bob));
